class EncryptionManager:
    @staticmethod
    def encrypt(input_bytes, provider_name='fernet'):
        provider_class_path = settings.PROVIDER_REGISTRY.get(provider_name)
        if not provider_class_path:
            raise ValueError(f"Provider {provider_name} not found")

        provider_class = import_string(provider_class_path)
        provider = provider_class()
        return provider.encrypt(input_bytes)

    @staticmethod
    def decrypt(encrypted_bytes, provider_name='fernet'):
        provider_class_path = settings.PROVIDER_REGISTRY.get(provider_name)
        if not provider_class_path:
            raise ValueError(f"Provider {provider_name} not found")

        provider_class = import_string(provider_class_path)
        provider = provider_class()
        return provider.decrypt(encrypted_bytes)

def import_string(dotted_path):
    module_path, class_name = dotted_path.rsplit('.', 1)
    module = __import__(module_path, fromlist=[class_name])
    return getattr(module, class_name)

